&=\frac{\lim _{t \rightarrow x} \frac{f(t)-f(x)}{t-x}}{\lim _{t \rightarrow x} \frac{g(t)-g(x)}{t-x}}

&=\frac{f^{\prime}(x)}{g^{\prime}(x)}

\end{aligned}

